import json
from pathlib import Path

from tim.cliagent import CliAgent


def _format_timestamp(raw_timestamp: str) -> str:
    date_part, time_part = raw_timestamp[:10], raw_timestamp[11:]
    time_part = time_part[:time_part.index("+")]
    return f"{date_part} {time_part}"


def _render_system_message(message_data: dict) -> str:
    content = message_data.get("content", "")
    return (
        f"<div class='message-system'><div class='message-content'>"
        f"<pre>{html.escape(content)}</pre></div></div>"
    )


def _render_user_message(message_data: dict) -> str:
    content = message_data.get("content", "")
    return (
        f"<div class='message user'><div class='message-content'>"
        f"<pre>{html.escape(content)}</pre></div></div>"
    )


def _render_tool_call(tool_call: dict) -> str:
    tool_id = tool_call.get("id", "unknown")
    tool_name = tool_call.get("name", "unknown")
    tool_args = tool_call.get("arguments", "{}")
    args_escaped = html.escape(tool_args)
    return (
        f"<details class='tool-call'><summary>Tool call <code>{html.escape(tool_name)} "
        f"{html.escape(tool_id)}</code></summary>"
        f"<pre>{args_escaped}</pre></details>"
    )


def _render_tool_response(message_data: dict) -> str:
    content = message_data.get("content", "")
    tool_id = message_data.get("id", "unknown")
    return (
        f"<details class='tool-output'><summary>Tool response <code>{html.escape(tool_id)}</code></summary>"
        f"<pre>{html.escape(content)}</pre></details>"
    )


def _render_assistant_message(message_data: dict) -> str:
    parts: list[str] = []

    reasoning = message_data.get("reasoning")
    if reasoning:
        parts.append(
            f"<details class='reasoning'><summary>Reasoning</summary>"
            f"<pre>{html.escape(reasoning)}</pre></details>"
        )

    tool_calls = message_data.get("tool_calls", [])
    for tool_call in tool_calls:
        parts.append(_render_tool_call(tool_call))

    content = message_data.get("content", "")
    if content:
        parts.append(
            f"<div class='message-content'><pre>{html.escape(content)}</pre></div>"
        )

    if not parts:
        return "<div class='message assistant'><div class='message-content'><pre></pre></div></div>"

    return f"<div class='message assistant'>" + "\n".join(parts) + "</div>"


def _render_message(message_data: dict) -> str:
    role = message_data.get("role", "")
    if role == "system":
        return _render_system_message(message_data)
    if role == "user":
        return _render_user_message(message_data)
    if role == "assistant":
        return _render_assistant_message(message_data)
    if role == "tool":
        return _render_tool_response(message_data)
    return ""


def _render_log_entry(entry: dict) -> str:
    source = entry.get("source", {})
    agent_name = source.get("agent", "Unknown")
    agent_instance = source.get("agent_instance", "")
    raw_timestamp = entry.get("at", "")
    message_data = entry.get("message", {})

    timestamp = _format_timestamp(raw_timestamp)
    agent_label = f"{agent_name} ({agent_instance})" if agent_instance else agent_name

    body = _render_message(message_data)

    return (
        f"<div class='log-entry'>"
        f"<div class='log-meta'>"
        f"<span class='timestamp'>{html.escape(timestamp)}</span>"
        f"<span class='agent-label'>{html.escape(agent_label)}</span>"
        f"</div>"
        f"<div class='log-body'>{body}</div>"
        f"</div>"
    )


def _collect_agent_name(entries: list[dict]) -> str:
    for entry in entries:
        agent_name = entry.get("source", {}).get("agent", "")
        if agent_name:
            return agent_name
    return "Unknown"


def _extract_time_range(entries: list[dict]) -> tuple[str, str]:
    if not entries:
        return "", ""
    first_timestamp = entries[0].get("at", "")
    last_timestamp = entries[-1].get("at", "")
    return _format_timestamp(first_timestamp), _format_timestamp(last_timestamp)


def html_from_log(log_file_path: str) -> str:
