        f"</div>"
    )

    entry_blocks = [_render_log_entry(entry) for entry in entries]
    body_content = "\n".join(entry_blocks)

    return (
        "<!DOCTYPE html>\n"
        "<html lang='en'>\n"
        "<head>\n"
        "<meta charset='utf-8'>\n"
        "<meta name='viewport' content='width=device-width, initial-scale=1'>\n"
